//! [ArceOS] hardware abstraction layer, provides unified APIs for
//! platform-specific operations.
//!
//! It does the bootstrapping and initialization process for the specified
//! platform, and provides useful operations on the hardware.
//!
//! Currently supported platforms (specify by cargo features):
//!
//! - `x86-pc`: Standard PC with x86_64 ISA.
//! - `riscv64-qemu-virt`: QEMU virt machine with RISC-V ISA.
//! - `aarch64-qemu-virt`: QEMU virt machine with AArch64 ISA.
//! - `aarch64-raspi`: Raspberry Pi with AArch64 ISA.
//! - `dummy`: If none of the above platform is selected, the dummy platform
//!    will be used. In this platform, most of the operations are no-op or
//!    `unimplemented!()`. This platform is mainly used for [cargo test].
//!
//! # Cargo Features
//!
//! - `smp`: Enable SMP (symmetric multiprocessing) support.
//! - `fp_simd`: Enable floating-point and SIMD support.
//! - `paging`: Enable page table manipulation.
//! - `irq`: Enable interrupt handling support.
//!
//! [ArceOS]: https://github.com/arceos-org/arceos
//! [cargo test]: https://doc.rust-lang.org/cargo/guide/tests.html

#![no_std]
#![feature(naked_functions)]

#[allow(unused_imports)]
#[macro_use]
extern crate log;

mod platform;

pub mod arch;
pub mod cpu;
pub mod mem;
pub mod time;
pub mod trap;

#[cfg(feature = "tls")]
pub mod tls;

#[cfg(feature = "irq")]
pub mod irq;

#[cfg(feature = "paging")]
pub mod paging;

/// Console input and output.
pub mod console {
    pub use super::platform::console::*;

    /// Write a slice of bytes to the console.
    pub fn write_bytes(bytes: &[u8]) {
        for c in bytes {
            putchar(*c);
        }
    }
}

/// Miscellaneous operation, e.g. terminate the system.
pub mod misc {
    pub use super::platform::misc::*;
}

pub mod port {
    pub use super::platform::port::*;
}

/// Multi-core operations.
#[cfg(feature = "smp")]
pub mod mp {
    pub use super::platform::mp::*;
}

pub use self::platform::platform_init;

#[cfg(feature = "smp")]
pub use self::platform::platform_init_secondary;

/// 架构相关的实现

#[cfg(target_arch = "riscv64")]
mod riscv;
#[cfg(target_arch = "riscv64")]
pub use self::riscv::*;

#[cfg(target_arch = "loongarch64")]
mod loongarch;
#[cfg(target_arch = "loongarch64")]
pub use self::loongarch::*;

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
compile_error!("Unsupported architecture");

#[macro_use]
mod macros;

mod context;
mod trap;

use memory_addr::{PhysAddr, VirtAddr};
use riscv::asm;
use riscv::register::{satp, sstatus, stvec};

pub use self::context::{GeneralRegisters, TaskContext, TrapFrame};

/// Allows the current CPU to respond to interrupts.
#[inline]
pub fn enable_irqs() {
    // Explicitly enable soft, timer, and external interrupts before raising SIE
    unsafe {
        riscv::register::sie::set_ssoft();
        riscv::register::sie::set_stimer();
        riscv::register::sie::set_sext();
        sstatus::set_sie();
    }
}

/// Makes the current CPU to ignore interrupts.
#[inline]
pub fn disable_irqs() {
    unsafe { sstatus::clear_sie() }
}

/// Returns whether the current CPU is allowed to respond to interrupts.
#[inline]
pub fn irqs_enabled() -> bool {
    sstatus::read().sie()
}

/// Relaxes the current CPU and waits for interrupts.
///
/// It must be called with interrupts enabled, otherwise it will never return.
#[inline]
pub fn wait_for_irqs() {
    unsafe { riscv::asm::wfi() }
}

/// Halt the current CPU.
#[inline]
pub fn halt() {
    disable_irqs();
    unsafe { riscv::asm::wfi() } // should never return
}

/// Reads the register that stores the current page table root.
///
/// Returns the physical address of the page table root.
#[inline]
pub fn read_page_table_root() -> PhysAddr {
    PhysAddr::from(satp::read().ppn() << 12)
}

/// Writes the register to update the current page table root.
///
/// # Safety
///
/// This function is unsafe as it changes the virtual memory address space.
pub unsafe fn write_page_table_root(root_paddr: PhysAddr) {
    let old_root = read_page_table_root();
    trace!("set page table root: {:#x} => {:#x}", old_root, root_paddr);
    if old_root != root_paddr {
        satp::set(satp::Mode::Sv39, 0, root_paddr.as_usize() >> 12);
        asm::sfence_vma_all();
    }
}

/// Flushes the TLB.
///
/// If `vaddr` is [`None`], flushes the entire TLB. Otherwise, flushes the TLB
/// entry that maps the given virtual address.
#[inline]
pub fn flush_tlb(vaddr: Option<VirtAddr>) {
    unsafe {
        if let Some(vaddr) = vaddr {
            asm::sfence_vma(0, vaddr.as_usize())
        } else {
            asm::sfence_vma_all();
        }
    }
}

/// Writes Supervisor Trap Vector Base Address Register (`stvec`).
#[inline]
pub fn set_trap_vector_base(stvec: usize) {
    unsafe { stvec::write(stvec, stvec::TrapMode::Direct) }
}

/// Reads the thread pointer of the current CPU.
///
/// It is used to implement TLS (Thread Local Storage).
#[inline]
pub fn read_thread_pointer() -> usize {
    let tp;
    unsafe { core::arch::asm!("mv {}, tp", out(reg) tp) };
    tp
}

/// Writes the thread pointer of the current CPU.
///
/// It is used to implement TLS (Thread Local Storage).
///
/// # Safety
///
/// This function is unsafe as it changes the CPU states.
#[inline]
pub unsafe fn write_thread_pointer(tp: usize) {
    core::arch::asm!("mv tp, {}", in(reg) tp)
}

/// Initializes CPU states on the current CPU.
///
/// On RISC-V, it sets the trap vector base address.
pub fn cpu_init() {
    extern "C" {
        fn trap_vector_base();
    }
    set_trap_vector_base(trap_vector_base as usize);
}

// MeteorOS/modules/axhal/src/arch/riscv/context.rs
// RISC-V 架构相关的上下文定义

use memory_addr::VirtAddr;
use riscv::register::sstatus::{self};

include_asm_marcos!();

/// 通用寄存器结构体
#[allow(missing_docs)]
#[repr(C)]
#[derive(Debug, Default, Clone)]
pub struct GeneralRegisters {
    pub ra: usize,
    pub sp: usize,
    pub gp: usize, // only valid for user traps
    pub tp: usize, // only valid for user traps
    pub t0: usize,
    pub t1: usize,
    pub t2: usize,
    pub s0: usize,
    pub s1: usize,
    pub a0: usize,
    pub a1: usize,
    pub a2: usize,
    pub a3: usize,
    pub a4: usize,
    pub a5: usize,
    pub a6: usize,
    pub a7: usize,
    pub s2: usize,
    pub s3: usize,
    pub s4: usize,
    pub s5: usize,
    pub s6: usize,
    pub s7: usize,
    pub s8: usize,
    pub s9: usize,
    pub s10: usize,
    pub s11: usize,
    pub t3: usize,
    pub t4: usize,
    pub t5: usize,
    pub t6: usize,
}

#[repr(C)]
#[derive(Debug, Default, Clone)]
pub struct TrapFrame {
    /// 通用寄存器
    pub regs: GeneralRegisters,
    pub sepc: usize,
    pub sstatus: usize,
}

impl TrapFrame {
    /// 初始化用户态应用的 TrapFrame 上下文
    pub fn app_init_context(entry: usize, sp: usize, user_gp: usize, _user_satp: usize) -> Self {
        let sstatus = sstatus::read();
        let sstatus_val = unsafe {
            (*(&sstatus as *const sstatus::Sstatus as *const usize) & !(1 << 8)) | (1 << 5)
        };

        let mut cx = Self { regs: GeneralRegisters::default(), sepc: entry, sstatus: sstatus_val };
        cx.regs.sp = sp;
        cx.regs.gp = user_gp;
        cx.regs.tp = 0;
        cx
    }
}
/// Saved hardware states of a task.
///
/// The context usually includes:
///
/// - Callee-saved registers
/// - Stack pointer register
/// - Thread pointer register (for thread-local storage, currently unsupported)
/// - FP/SIMD registers
///
/// On context switch, current task saves its context from CPU to memory,
/// and the next task restores its context from memory to CPU.
#[allow(missing_docs)]
#[repr(C)]
#[derive(Debug, Default)]
pub struct TaskContext {
    pub ra: usize, // return address (x1)
    pub sp: usize, // stack pointer (x2)

    pub s0: usize, // x8-x9
    pub s1: usize,

    pub s2: usize, // x18-x27
    pub s3: usize,
    pub s4: usize,
    pub s5: usize,
    pub s6: usize,
    pub s7: usize,
    pub s8: usize,
    pub s9: usize,
    pub s10: usize,
    pub s11: usize,

    pub tp: usize,
    pub sscratch: usize,
    pub satp: usize,
    // TODO: FP states
}

impl TaskContext {
    /// Creates a dummy context for a new task.
    ///
    /// Note the context is not initialized, it will be filled by [`switch_to`]
    /// (for initial tasks) and [`init`] (for regular tasks) methods.
    ///
    /// [`init`]: TaskContext::init
    /// [`switch_to`]: TaskContext::switch_to
    pub const fn new() -> Self {
        unsafe { core::mem::MaybeUninit::zeroed().assume_init() }
    }

    /// Initializes the context for a new task, with the given entry point and
    /// kernel stack.
    pub fn init(&mut self, entry: usize, kstack_top: VirtAddr, tls_area: VirtAddr) {
        self.sp = kstack_top.as_usize();
        self.ra = entry;
        self.tp = tls_area.as_usize();
    }

    pub fn initial_context(entry: usize, kstack_top: usize, satp: usize) -> Self {
        let mut ctx = Self::new();
        ctx.ra = entry;
        ctx.sp = kstack_top;
        ctx.satp = satp;
        #[cfg(feature = "tls")]
        {
            ctx.tp = super::read_thread_pointer();
        }
        ctx
    }

    /// Switches to another task.
    ///
    /// It first saves the current task's context from CPU to this place, and then
    /// restores the next task's context from `next_ctx` to CPU.
    pub fn switch_to(&mut self, next_ctx: &Self) {
        #[cfg(feature = "tls")]
        {
            self.tp = super::read_thread_pointer();
            unsafe { super::write_thread_pointer(next_ctx.tp) };
        }
        unsafe {
            // TODO: switch FP states
            context_switch(self, next_ctx)
        }
    }
}

#[naked]
unsafe extern "C" fn context_switch(_current_task: &mut TaskContext, _next_task: &TaskContext) {
    core::arch::naked_asm!(
        "
        // save old context (callee-saved registers)
        sd      ra, 0*8(a0)
        sd      sp, 1*8(a0)
        sd      s0, 2*8(a0)
        sd      s1, 3*8(a0)
        sd      s2, 4*8(a0)
        sd      s3, 5*8(a0)
        sd      s4, 6*8(a0)
        sd      s5, 7*8(a0)
        sd      s6, 8*8(a0)
        sd      s7, 9*8(a0)
        sd      s8, 10*8(a0)
        sd      s9, 11*8(a0)
        sd      s10, 12*8(a0)
        sd      s11, 13*8(a0)

        // restore new context
        ld      s11, 13*8(a1)
        ld      s10, 12*8(a1)
        ld      s9, 11*8(a1)
        ld      s8, 10*8(a1)
        ld      s7, 9*8(a1)
        ld      s6, 8*8(a1)
        ld      s5, 7*8(a1)
        ld      s4, 6*8(a1)
        ld      s3, 5*8(a1)
        ld      s2, 4*8(a1)
        ld      s1, 3*8(a1)
        ld      s0, 2*8(a1)
        ld      sp, 1*8(a1)
        ld      ra, 0*8(a1)

        ret"
    )
}

// MeteorOS/axhal/src/arch/riscv/trap.rs
// RISC-V 特定的陷阱处理程序实现

#[cfg(feature = "paging")]
use crate::trap::handle_page_fault;
#[cfg(feature = "paging")]
use page_table::MappingFlags;
use riscv::register::scause::{self, Exception as E, Interrupt as I, Trap};
use riscv::register::stval;

use super::TrapFrame;

include_asm_marcos!();

core::arch::global_asm!(
    include_str!("trap.S"),
    trapframe_size = const core::mem::size_of::<TrapFrame>(),
);

fn handle_breakpoint(sepc: &mut usize) {
    debug!("Exception(Breakpoint) @ {:#x} ", sepc);
    *sepc += 2
}

#[no_mangle]
fn riscv_trap_handler(tf: &mut TrapFrame, mut _from_user: bool) {
    let scause = scause::read();
    let addr = stval::read();
    let cause = scause.cause();
    let is_timer = matches!(cause, Trap::Interrupt(I::SupervisorTimer));
    let scause_bits = scause.bits();
    if _from_user || !is_timer {
        // Log raw trap info (including stval) to see repeated traps from user space.
        debug!(
            "trap raw: scause_bits={:#x} cause={:?} stval={:#x} sepc={:#x} from_user={}",
            scause_bits, cause, addr, tf.sepc, _from_user
        );
    }
    if !is_timer {
        debug!(
            "trap enter: cause={:?} ({:#x}) from_user={} sepc={:#x} stval={:#x}",
            cause,
            scause.bits(),
            _from_user,
            tf.sepc,
            addr
        );
    }

    // 如果trap来自用户态，则在此处进行预先抢占检查。
    // 定时器IRQ会设置预抢占标志；通过在用户陷阱的最开始检查，我们可以在继续进行系统调用/信号/IO处理之前
    // 服务挂起的抢占请求，从而减少延迟并避免看起来像FIFO的分组用户空间输出。
    if _from_user {
        // 使用trap接口调用更高层次的运行时的抢占检查
        //（避免从axhal crate添加对axprocess的直接依赖）。
        crate::trap::check_preempt_pending();
    }
    match cause {
        Trap::Exception(E::UserEnvCall) => {
            #[cfg(feature = "monolithic")]
            {
                // Extract syscall ID (a7) and arguments (a0-a5) per RISC-V calling convention
                let syscall_id = tf.regs.a7;
                let args = [tf.regs.a0, tf.regs.a1, tf.regs.a2, tf.regs.a3, tf.regs.a4, tf.regs.a5];
                // 保存原始 sepc，以便我们可以检测到故意修改陷阱框架的系统调用
                let orig_sepc = tf.sepc;
                let ret = crate::trap::handle_syscall(syscall_id, args, tf);

                if syscall_id != 139 && syscall_id != 221 {
                    tf.sepc += 4;
                }

                // 检查系统调用处理程序是否正确更新了 sepc，如果 sepc 仍然指向用户空间地址，则记录一个错误日志
                if tf.sepc < 0x10000 {
                    axlog::error!(
                        "BUG: sepc={:#x} after syscall {} (orig={:#x}), a0={:#x}",
                        tf.sepc, syscall_id, orig_sepc, tf.regs.a0
                    );
                }

                tf.regs.a0 = ret as usize;
            }
            #[cfg(not(feature = "monolithic"))]
            {
                tf.sepc += 4; // Advance past ecall instruction
            }
        }
        Trap::Exception(E::LoadPageFault) => {
            #[cfg(feature = "paging")]
            handle_page_fault(addr.into(), MappingFlags::READ, tf);
            #[cfg(not(feature = "paging"))]
            panic!("Load page fault @ {:#x}", addr);
        }
        Trap::Exception(E::StorePageFault) => {
            #[cfg(feature = "paging")]
            handle_page_fault(addr.into(), MappingFlags::WRITE, tf);
            #[cfg(not(feature = "paging"))]
            panic!("Store page fault @ {:#x}", addr);
        }
        Trap::Exception(E::InstructionPageFault) => {
            #[cfg(feature = "paging")]
            handle_page_fault(addr.into(), MappingFlags::EXECUTE, tf);
            #[cfg(not(feature = "paging"))]
            panic!("Instruction page fault @ {:#x}", addr);
        }
        Trap::Exception(E::Breakpoint) => handle_breakpoint(&mut tf.sepc),
        Trap::Interrupt(_) => {
            crate::trap::handle_irq(scause.bits());
        }
        _ => {
            panic!(
                "Unhandled trap {:?} @ {:#x}, stval={:#x}:\n{:#x?}",
                scause.cause(),
                tf.sepc,
                addr,
                tf
            );
        }
    }
    if !is_timer {
        debug!(
            "trap pre-signal: cause={:?} sepc={:#x} sp={:#x} a0={:#x} a1={:#x}",
            cause, tf.sepc, tf.regs.sp, tf.regs.a0, tf.regs.a1
        );
    }

    // Only deliver signals for user traps that are not timer interrupts; timers just return.
    if _from_user && !is_timer {
        crate::trap::handle_signal(tf);
    }

    if !is_timer {
        debug!(
            "trap exit:  cause={:?} sepc={:#x} sp={:#x} a0={:#x} a1={:#x}",
            cause, tf.sepc, tf.regs.sp, tf.regs.a0, tf.regs.a1
        );
    }

    if _from_user && tf.sepc < 0x10000 {
        axlog::error!(
            "BUG: sepc={:#x} is invalid before returning to user! cause={:?} sp={:#x} a0={:#x} a7={:#x}",
            tf.sepc, cause, tf.regs.sp, tf.regs.a0, tf.regs.a7
        );
    }

    // 在返回用户态之前再次检查抢占请求
    if _from_user {
        crate::trap::check_preempt_pending();
    }
}

