/// 切换当前任务，将当前任务挂起并运行下一个任务。
pub fn yield_now() {
    if let Some(task) = current_task() {
        let mut inner = task.inner_exclusive_access();
        let ptr = &mut inner.task_cx as *mut TaskContext;
        drop(inner);
        schedule(ptr);
    }
}

/// 默认时间片长度（单位：调度时钟滴答数）
pub const TIME_SLICE_DEFAULT: usize = 100;

/// 被调度器在每个定时器滴答上调用。用于实现基于时间片的轮转调度。
pub fn on_timer_tick_rr() {
    if let Some(curr) = current_task() {
        // 进入独占访问（在此设计中IRQ上下文中安全）
        let mut inner = curr.inner_exclusive_access();
        // 仅适用于非空闲任务
        if curr.get_process_id() != IDLE_PID {
            // 如果时间片尚未用尽，则递减剩余时间片计数
            if inner.time_slice_remain > 0 {
                inner.time_slice_remain -= 1;
            }
            // 如果时间片用尽，则重置并请求抢占
            if inner.time_slice_remain == 0 {
                // 重置时间片并请求抢占
                inner.time_slice_remain = TIME_SLICE_DEFAULT;
                inner.need_resched.store(true, Ordering::Release);
            }
        }
    }
}

pub struct TimerInterfaceImpl;

#[crate_interface::impl_interface]
impl axhal::time::TimerInterface for TimerInterfaceImpl {
    fn check_timer() {
        check_timer()
    }
    fn add_timer(expire_ms: usize, task_ptr: usize) {
        let ptr = task_ptr as *const TaskControlBlock;
        unsafe {
            Arc::increment_strong_count(ptr);
            let task = Arc::from_raw(ptr);
            add_timer(expire_ms, task);
        }
    }
}

struct YieldImpl;

#[crate_interface::impl_interface]
impl axsync::Yield for YieldImpl {
    fn yield_now() {
        suspend_current_and_run_next();
    }

    fn run_ready_tasks() -> bool {
        run_tasks_once()
    }
}

// 提供 kernel_guard 实现，以便内核抢占启用/禁用
// 是中央集中在 axprocess 的抢占计数器中。 这避免了不同任务子系统之间的分歧。
#[cfg(feature = "preempt")]
struct KernelGuardIfImpl;

#[cfg(feature = "preempt")]
#[crate_interface::impl_interface]
impl kernel_guard::KernelGuardIf for KernelGuardIfImpl {
    fn enable_preempt() {
        // 当内核保护重新启用抢占时，让 axprocess 决定是否重新调度（传递 `true` 以便最外层启用触发检查）。
        enable_preempt_current(true);
    }

    fn disable_preempt() {
        disable_preempt_current();
    }
}

// 挂起当前任务并运行下一个任务
pub fn suspend_current_and_run_next() {
    let task = take_current_task().unwrap();

    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut TaskContext;
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    add_task(task);
    schedule(task_cx_ptr);
}

use core::sync::atomic::Ordering;

/// 设置当前任务的抢占待处理标志。
pub fn set_preempt_pending(pending: bool) {
    if let Some(curr) = current_task() {
        let inner = curr.inner_exclusive_access();
        inner.need_resched.store(pending, Ordering::Release);
    }
}

/// 检查当前任务是否有待抢占且可以被抢占。 如果是，则执行挂起并运行下一个操作。
pub fn current_check_preempt_pending() {
    if let Some(curr) = current_task() {
        // 检查原子变量，在 UPIntrFreeCell 提供的独占访问下。
        let inner = curr.inner_exclusive_access();
        let pending = inner.need_resched.load(Ordering::Acquire);
        // 嵌套计数，表示当前任务有多少次禁用抢占的调用
        let disabled = inner.preempt_disable_count.load(Ordering::Acquire);
        // 检查当前任务是否有待抢占且可以被抢占
        if pending && disabled == 0 {
            drop(inner);
            // 清除待处理标志以避免竞争条件。
            let inner2 = curr.inner_exclusive_access();
            // 设置标志为假，表示当前任务不再需要抢占
            inner2.need_resched.store(false, Ordering::Release);
            drop(inner2);
            suspend_current_and_run_next();
        }
    }
}

/// 取消当前任务的抢占（增加嵌套计数）。
pub fn disable_preempt_current() {
    if let Some(curr) = current_task() {
        let inner = curr.inner_exclusive_access();
        // 增加嵌套计数，表示当前任务处于不可抢占状态
        inner.preempt_disable_count.fetch_add(1, Ordering::Relaxed);
    }
}

/// 启用当前任务的抢占（减少嵌套计数）。
/// 如果 `resched` 为真且这是最外层启用，则检查待处理并重新调度。
pub fn enable_preempt_current(resched: bool) {
    if let Some(curr) = current_task() {
        let inner = curr.inner_exclusive_access();
        // 如果这是最外层启用，则减少嵌套计数
        if inner.preempt_disable_count.fetch_sub(1, Ordering::Relaxed) == 1 && resched {
            drop(inner);
            // 检查待处理并重新调度
            current_check_preempt_pending();
        }
    }
}

/// 阻塞当前任务并运行下一个任务。
pub fn yield_current_and_run_next() {
    let task = current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Ready;
    let task_cx_ptr = &mut task_inner.task_cx as *mut TaskContext;
