impl ProcessControlBlock {
    // 创建新进程并导入 ELF 文件
    pub fn new(elf_data: &[u8]) -> Arc<Self> {
        // memory_set 包含 内核映射以及elf program headers/trampoline/trap context/user stack
        let (memory_set, ustack_base, entry_point, user_gp, _load_base, _tls_info) =
            MemorySet::from_elf(elf_data);
        // 分配一个 pid
        let pid_handle = pid_alloc();

        // Create shared ProcessData (like Starry)
        let process_data = ProcessData::new(memory_set);

        let process = Arc::new(Self {
            pid: pid_handle,
            process_data: Arc::clone(&process_data),
            name: Arc::new(Mutex::new(String::new())),
            is_zombie: Arc::new(Mutex::new(false)),
            parent: Arc::new(Mutex::new(None)),
            children: Arc::new(Mutex::new(Vec::new())),
            exit_code: Arc::new(Mutex::new(0)),
            signals: Arc::new(Mutex::new(SignalFlags::empty())),
        });

        // 创建一个主线程
        let task = Arc::new(TaskControlBlock::new(Arc::clone(&process), ustack_base, true));
        // 初始化主线程的用户资源
        let task_inner = task.inner_exclusive_access();
        let ustack_top = task_inner.res.as_ref().unwrap().ustack_top();
        drop(task_inner);

