// 线程控制块
pub struct TaskControlBlock {
    // 记录所属进程
    pub process: Weak<ProcessControlBlock>,
    // 内核栈
    pub kstack: KernelStack,
    // 内核线程入口
    pub entry: Option<usize>,
    // axtask 任务引用
    pub ax_task: AxTaskRef,
    pub inner: UPIntrFreeCell<TaskControlBlockInner>,
}

impl TaskControlBlock {
    pub fn inner_exclusive_access(&self) -> UPIntrRefMut<'_, TaskControlBlockInner> {
        self.inner.exclusive_access()
    }

    pub fn get_user_token(&self) -> usize {
        let process = self.process.upgrade().unwrap();
        let memory_set = process.process_data.memory_set.lock();
        memory_set.token()
    }

    pub fn get_tid(&self) -> usize {
        self.inner_exclusive_access().res.as_ref().map(|r| r.tid).unwrap_or(0)
    }
}

pub struct TaskControlBlockInner {
    // 线程资源：用户栈、trap frame 等
    pub res: Option<TaskUserRes>,
    // 线程上下文
    pub task_cx: TaskContext,
    // 线程状态
    pub task_status: TaskStatus,
    // 退出代码
    pub exit_code: Option<i32>,
    // 抢占支持：该任务是否有待处理的抢占请求
    pub need_resched: AtomicBool,
    // 计数器，用于在临界区禁用抢占，表示当前任务有多少次禁用抢占的调用
    pub preempt_disable_count: AtomicUsize,
    // 剩余时间片滴答数。每次定时器滴答时递减。
    // 当它达到零时，调度程序应该抢占此任务。
    pub time_slice_remain: usize,
    // 子线程退出后，清除该地址处的 TID 值
    pub clear_child_tid: usize,
}

impl TaskControlBlockInner {
    pub fn get_trap_cx(&self) -> &'static mut TrapFrame {
        panic!("get_trap_cx() is deprecated - trap frame is now on kernel stack");
    }

    #[allow(unused)]
    fn get_status(&self) -> TaskStatus {
        self.task_status
    }
}

impl TaskControlBlock {
    pub fn new(
        process: Arc<ProcessControlBlock>,
        ustack_base: usize,
        alloc_user_res: bool,
    ) -> Self {
        let res = TaskUserRes::new(Arc::clone(&process), ustack_base, alloc_user_res);
        let kstack = kstack_alloc();
        let kstack_top = kstack.get_top();
        let pid = process.getpid();
        let name = alloc::format!("proc-{}", pid);
        let ax_task = axtask::spawn_unqueued(
            || loop {
                axtask::yield_now();
            },
            name,
            4096,
        );
        ax_task.set_state(TaskState::Running);

        Self {
            process: Arc::downgrade(&process),
            kstack,
            entry: None,
            ax_task,
            inner: unsafe {
                UPIntrFreeCell::new(TaskControlBlockInner {
                    res: Some(res),
                    task_cx: TaskContext::initial_context(
                        task_entry as usize,
                        kstack_top - core::mem::size_of::<TrapFrame>(),
                        axmem::kernel_token(),
                    ),
                    task_status: TaskStatus::Ready,
                    exit_code: None,
                    need_resched: AtomicBool::new(false),
                    preempt_disable_count: AtomicUsize::new(0),
                    time_slice_remain: crate::TIME_SLICE_DEFAULT,
                    clear_child_tid: 0,
                })
            },
        }
    }
}

