#[unsafe(no_mangle)]
/// 本线程将会执行的函数
extern "C" fn task_entry() {
    // 使能中断
    axhal::arch::enable_irqs();
    let task_arc: Arc<TaskControlBlock> = crate::current_task().expect("current task missing");

    // 设置当前任务指针（TLS）
    unsafe {
        axhal::cpu::set_current_task_ptr(Arc::as_ptr(&task_arc));
    }
    // 检查是否是Idle任务
    let is_idle = task_arc.get_process_id() == IDLE_PID;

    let entry = task_arc.entry;

    // 根据是否有entry决定进入内核态还是用户态
    if let Some(entry) = entry {
        // 有entry，说明是初次运行的任务
        if is_idle {
            // Idle任务直接进入内核态执行
            let entry_fn: extern "C" fn() = unsafe { core::mem::transmute(entry) };
            entry_fn();
        } else {
            // 非Idle任务，首次进入用户态
            let frame_address = task_arc.kstack.get_top();
            let user_satp = task_arc.get_user_token();
            // 首次进入用户态
            first_into_user(frame_address as usize, user_satp);
        }
    } else if !is_idle {
        // 无entry，说明是已经exec过的用户态任务，继续进入用户态
        let frame_address = task_arc.kstack.get_top();
        let user_satp = task_arc.get_user_token();

        let _current_sp: usize;
        let _current_sscratch: usize;

        // 进入用户态
        first_into_user(frame_address as usize, user_satp);
    }
    // Idle任务或其他内核态任务执行完毕后退出
    crate::exit_current_and_run_next(0);
}

impl Drop for TaskControlBlock {
    fn drop(&mut self) {
        if let Some(process) = self.process.upgrade() {
            let (bottom, top) = self.kstack.get_range();
            let mut memory_set = process.process_data.memory_set.lock();
            let mut va = bottom;
            while va < top {
                memory_set.unmap_one_page(VirtAddr::from(va));
                va += PAGE_SIZE;
            }
        }
    }
}

