// 运行任务调度器一次，执行一个任务
pub fn run_tasks_once() -> bool {
    axhal::arch::disable_irqs();
    let mut processor = (&*PROCESSOR).lock();
    let mut ran_task = false;
    if let Some(task) = fetch_task() {
        ran_task = true;
        let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();

        let mut task_inner = task.inner_exclusive_access();
        task_inner.task_status = TaskStatus::Running;
        task.ax_task.set_state(TaskState::Running);
        let next_task_cx_ptr = &task_inner.task_cx as *const TaskContext;

        drop(task_inner);

        let old_current = processor.current.clone();
        processor.current = Some(task.clone());

        let old_ptr: *const u8 = axhal::cpu::current_task_ptr();

        drop(processor);

        unsafe {
            let ptr = Arc::into_raw(task.ax_task.clone());
            axhal::cpu::set_current_task_ptr(ptr);
        }

        unsafe {
            __switch(idle_task_cx_ptr, next_task_cx_ptr);
            let leaked_ptr: *const u8 = axhal::cpu::current_task_ptr();
            axhal::cpu::set_current_task_ptr(old_ptr);
            if !leaked_ptr.is_null() && leaked_ptr != old_ptr {
                axtask::drop_task_ptr(leaked_ptr);
            }
        }

        let mut processor = (&*PROCESSOR).lock();
        processor.current = old_current;
    }

    if ran_task {
        axhal::arch::enable_irqs();
    }
    // 返回是否执行了任务
    ran_task
}

/// 获取当前任务的所有权
pub fn take_current_task() -> Option<Arc<TaskControlBlock>> {
    (&*PROCESSOR).lock().take_current()
}

/// 获取当前任务
pub fn current_task() -> Option<Arc<TaskControlBlock>> {
    (&*PROCESSOR).lock().current()
}

pub fn current_process() -> Arc<ProcessControlBlock> {
    current_task()
        .and_then(|t| t.process.upgrade())
        .expect("[current_process] no current process")
}

pub fn current_user_token() -> usize {
    let task = current_task().unwrap();
    task.get_user_token()
}

// 获取当前任务的 TrapFrame 引用
pub fn current_trap_cx() -> &'static mut TrapFrame {
    let task = current_task().unwrap();
    let kstack_top = task.kstack.get_top();
    let tf_ptr = (kstack_top - core::mem::size_of::<TrapFrame>()) as *mut TrapFrame;
    unsafe { &mut *tf_ptr }
}

pub fn current_trap_cx_user_va() -> usize {
    current_task().unwrap().inner_exclusive_access().res.as_ref().unwrap().trap_cx_user_va()
}

pub fn current_kstack_top() -> usize {
    if let Some(task) = current_task() {
        task.kstack.get_top()
    } else {
        let mut boot_stack_top;
        unsafe { asm!("la {},boot_stack_top",out(reg) boot_stack_top) };
        boot_stack_top
    }
}

pub fn schedule(switched_task_cx_ptr: *mut TaskContext) {
    if let Some(next_task) = fetch_task() {
        let mut next_inner = next_task.inner_exclusive_access();
        next_inner.task_status = TaskStatus::Running;
        next_task.ax_task.set_state(TaskState::Running);
        let next_task_cx_ptr = &next_inner.task_cx as *const TaskContext;
        drop(next_inner);

        let mut processor = (&*PROCESSOR).lock();
        processor.current = Some(next_task.clone());
        drop(processor);

        let old_ptr: *const u8 = axhal::cpu::current_task_ptr();
        unsafe {
            let ptr = Arc::into_raw(next_task.ax_task.clone());
            axhal::cpu::set_current_task_ptr(ptr);
            if !old_ptr.is_null() && old_ptr != ptr as *const u8 {
                axtask::drop_task_ptr(old_ptr);
            }
            __switch(switched_task_cx_ptr, next_task_cx_ptr);
        }
    } else {
        let mut processor = (&*PROCESSOR).lock();
        processor.current = None;
        let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
        drop(processor);

        let old_ptr: *const u8 = axhal::cpu::current_task_ptr();
        unsafe {
            axhal::cpu::set_current_task_ptr(core::ptr::null::<u8>());
            if !old_ptr.is_null() {
                axtask::drop_task_ptr(old_ptr);
            }
            __switch(switched_task_cx_ptr, idle_task_cx_ptr);
        }
    }
}

