fn find_global_pointer(elf: &xmas_elf::ElfFile) -> Option<usize> {
    let mut sdata_min = usize::MAX;
    let mut sdata_max = 0;

    for section in elf.section_iter() {
        if let Ok(ty) = section.get_type() {
            if ty == ShType::SymTab || ty == ShType::DynSym {
                if let Ok(SectionData::SymbolTable64(symtab)) = section.get_data(elf) {
                    for sym in symtab {
                        if let Ok(name) = sym.get_name(elf) {
                            if name == "__global_pointer$" {
                                return Some(sym.value() as usize);
                            }
                        }
                    }
                }
            }
        }

        if let Ok(name) = section.get_name(elf) {
            if name == ".sdata" || name == ".sbss" {
                let start = section.address() as usize;
                let end = start.saturating_add(section.size() as usize);
                sdata_min = sdata_min.min(start);
                sdata_max = sdata_max.max(end);
            }
        }
    }

    if sdata_max > sdata_min {
        let computed_gp = sdata_min + 0x800;
        Some(computed_gp)
    } else {
        None
    }
}

