pub fn syscall(syscall_id: usize, args: [usize; 6], tf: &mut TrapFrame) -> isize {
    let syscall_name = match SyscallId::try_from(syscall_id) {
        Ok(id) => id,
        Err(_) => {
            error!("Unsupported syscall_id: {}", syscall_id);
            return -LinuxError::ENOSYS.code() as isize;
        }
    };

    let curr_pid = axprocess::current_process().getpid();

    debug!(
        "[syscall-trace] pid={} enter id={} ({:?}) args=[{:#x}, {:#x}, {:#x}, {:#x}, {:#x}, {:#x}]",
        curr_pid, syscall_id, syscall_name, args[0], args[1], args[2], args[3], args[4], args[5]
    );

    use SyscallId::*;
    let ret = match syscall_name {
        PSELECT6 => select::syscall_pselect6(args),
        PPOLL => select::syscall_ppoll(args),
