        MKDIRAT => fs::syscall_mkdirat(args),
        UNLINKAT => fs::syscall_unlinkat(args),
        SYMLINKAT => fs::syscall_symlinkat(args),
        LINKAT => fs::syscall_linkat(args),
        READLINKAT => fs::syscall_readlinkat(args),
        RENAMEAT2 => fs::syscall_renameat2(args),
        CHDIR => fs::syscall_chdir(args),
        GETCWD => fs::syscall_getcwd(args),

