pub struct Dentry {
    /// component name
    pub name: Mutex<String>,

    /// parent dentry
    pub parent: Mutex<Option<Weak<Dentry>>>,

    /// child dentries
    pub children: Mutex<BTreeMap<String, Arc<Dentry>>>,

    /// associated inode
    ///
    /// None => negative dentry
    pub inode: Mutex<Option<VfsNodeRef>>,
}

impl Dentry {
    /// create root dentry
    pub fn new_root(inode: VfsNodeRef) -> Arc<Self> {
        Arc::new(Self {
            name: Mutex::new("/".into()),
            parent: Mutex::new(None),
            children: Mutex::new(BTreeMap::new()),
            inode: Mutex::new(Some(inode)),
        })
    }

    /// create normal dentry
    pub fn new(name: String, parent: &Arc<Dentry>, inode: Option<VfsNodeRef>) -> Arc<Self> {
        Arc::new(Self {
            name: Mutex::new(name),
            parent: Mutex::new(Some(Arc::downgrade(parent))),
            children: Mutex::new(BTreeMap::new()),
            inode: Mutex::new(inode),
        })
    }

    /// whether dentry is negative
    pub fn is_negative(&self) -> bool {
        self.inode.lock().is_none()
    }

    /// get inode
    pub fn inode(&self) -> AxResult<VfsNodeRef> {
        self.inode.lock().clone().ok_or(AxError::NotFound)
    }

    /// get inode optionally
    pub fn get_inode(&self) -> Option<VfsNodeRef> {
        self.inode.lock().clone()
    }

    /// set inode
    ///
    /// negative -> positive
    pub fn set_inode(&self, inode: VfsNodeRef) {
        *self.inode.lock() = Some(inode);
    }

    /// clear inode
    ///
    /// positive -> negative
    pub fn clear_inode(&self) {
        *self.inode.lock() = None;
    }

    /// get parent dentry
    pub fn parent(&self) -> Option<Arc<Dentry>> {
        self.parent.lock().as_ref()?.upgrade()
    }

    /// update parent
    pub fn set_parent(&self, parent: &Arc<Dentry>) {
        *self.parent.lock() = Some(Arc::downgrade(parent));
    }

    /// lookup cached child
    pub fn get_child(&self, name: &str) -> Option<Arc<Dentry>> {
        self.children.lock().get(name).cloned()
    }

    /// insert child dentry
    pub fn insert_child(&self, child: Arc<Dentry>) {
        let name = child.name.lock().clone();

        self.children.lock().insert(name, child);
    }

