pub struct InodeFile {
    /// opened path (mount + dentry)
    pub path: Path,

    /// inode capability
    pub node: WithCap<VfsNodeRef>,

    /// runtime file state
    pub state: Mutex<FileState>,

    /// file operations
    pub ops: &'static dyn FileOps,
}

impl InodeFile {
    pub fn new(path: Path, ops: &'static dyn FileOps, opts: &OpenOptions) -> Self {
        let inode = path.dentry.inode().unwrap();

        #[cfg(feature = "page-cache")]
        {
            let attr = inode.get_attr().unwrap();
            PAGE_CACHE.create_mapping(attr.device, attr.ino as u64, inode.clone());
        }

        Self {
            path,
            node: WithCap::new(inode, opts.into()),
            state: Mutex::new(FileState::new(opts.can_append())),
            ops,
        }
    }
}

impl InodeFile {
    /// full opened path
    pub fn path(&self) -> &Path {
        &self.path
    }

    /// opened dentry
    pub fn dentry(&self) -> &Arc<Dentry> {
        &self.path.dentry
    }

    /// opened mount
    pub fn mount(&self) -> &Arc<MountPoint> {
        &self.path.mount
    }

    /// access inode with capability check
    pub fn access_node(&self, cap: Cap) -> AxResult<&VfsNodeRef> {
        self.node.access_or_err(cap, AxError::PermissionDenied)
    }

    /// readable
    pub fn readable(&self) -> bool {
        self.node.cap().contains(Cap::READ)
    }

    /// writable
    pub fn writable(&self) -> bool {
        self.node.cap().contains(Cap::WRITE)
    }

    /// read all content
    pub fn read_all(&self) -> AxResult<Vec<u8>> {
        let size = self.get_attr()?.size;
        let mut out = Vec::with_capacity(size as usize);

        let mut offset = 0;

        let mut buf = [0u8; 4096];

        while offset < size {
            let n = self.read_at_raw(offset, &mut buf)?;
            if n == 0 {
                break;
            }

            out.extend_from_slice(&buf[..n]);
            offset += n as u64;
        }

        Ok(out)
    }

