impl MountNamespace {
    pub fn new() -> Self {
        Self { mounts: RwLock::new(Vec::new()) }
    }

    pub fn mounts(&self) -> Vec<Arc<MountPoint>> {
        self.mounts.read().clone()
    }

    /// lookup mounted child fs
    pub fn lookup_mount(
        &self,
        mount: &Arc<MountPoint>,
        dentry: &Arc<Dentry>,
    ) -> Option<Arc<MountPoint>> {
        self.mounts
            .read()
            .iter()
            .find(|m| {
                Arc::ptr_eq(&m.mountpoint, dentry)
                    && match &m.parent {
                        Some(parent) => Arc::ptr_eq(parent, mount),
                        None => false,
                    }
            })
            .cloned()
    }

    /// mount fs
    pub fn mount(&self, path: &str, fs: Arc<dyn VfsOps>) -> AxResult {
        if path == "/" {
            return ax_err!(InvalidInput);
        }

        let mountpoint = PathWalker::new(None, path, true)?.walk()?;

        let inode = mountpoint.inode()?;

        let attr = inode.get_attr()?;

        if !attr.is_dir() {
            return ax_err!(NotADirectory);
        }

        let root_inode = fs.root_dir();

        let root = Dentry::new("/".into(), &mountpoint.dentry, Some(root_inode.clone()));

        let sb = Arc::new(SuperBlock { root: root_inode, fs });

        self.mounts.write().push(Arc::new(MountPoint {
            parent: Some(mountpoint.mount),
            mountpoint: mountpoint.dentry,
            root,
            sb,
        }));

        Ok(())
    }

