/// 虚拟 ELF 数据
/// 这是一个最小但有效的 RISC-V 64 位 ELF 文件
/// 包含: ELF header, PT_LOAD program header, 以及简单的代码段
// 对齐的 ELF 数据结构
#[repr(align(8))]
struct AlignedBytes<const N: usize>([u8; N]);

// DUMMY ELF - 一个简单的无限循环程序
// 使用静态变量来保证8字节对齐
static DUMMY_ELF_DATA: AlignedBytes<264> = AlignedBytes([
    // ELF Header (64 bytes, offsets 0x00-0x3F)
    0x7f, 0x45, 0x4c, 0x46, // e_ident[EI_MAG]: ELF magic
    0x02, // e_ident[EI_CLASS]: ELFCLASS64
    0x01, // e_ident[EI_DATA]: ELFDATA2LSB (little endian)
    0x01, // e_ident[EI_VERSION]: EV_CURRENT
    0x00, // e_ident[EI_OSABI]: ELFOSABI_NONE
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // e_ident[EI_PAD]: padding
    0x02, 0x00, // e_type: ET_EXEC (executable)
    0xf3, 0x00, // e_machine: EM_RISCV (243)
    0x01, 0x00, 0x00, 0x00, // e_version: EV_CURRENT
    0x00, 0x01, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, // e_entry: 0x10100 (entry point)
    0x40, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // e_phoff: 64 (program header offset)
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // e_shoff: 0 (no section headers)
    0x00, 0x00, 0x00, 0x00, // e_flags: 0
    0x40, 0x00, // e_ehsize: 64 (ELF header size)
    0x38, 0x00, // e_phentsize: 56 (program header entry size)
    0x01, 0x00, // e_phnum: 1 (one program header)
    0x00, 0x00, // e_shentsize: 0 (no section headers)
    0x00, 0x00, // e_shnum: 0
    0x00, 0x00, // e_shstrndx: 0
    // Program Header (56 bytes, offsets 0x40-0x77)
    0x01, 0x00, 0x00, 0x00, // p_type: PT_LOAD
    0x05, 0x00, 0x00, 0x00, // p_flags: PF_R | PF_X (readable + executable)
    0x00, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // p_offset: 0x100 (file offset)
    0x00, 0x01, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, // p_vaddr: 0x10100 (virtual address)
    0x00, 0x01, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, // p_paddr: 0x10100 (physical address)
    0x08, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // p_filesz: 8 (size in file)
    0x08, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // p_memsz: 8 (size in memory)
    0x00, 0x10, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // p_align: 0x1000 (4KB alignment)
    // Padding to reach offset 0x100 (where code starts)
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0x78-0x7f
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0x80-0x87
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0x88-0x8f
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0x90-0x97
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0x98-0x9f
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xa0-0xa7
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xa8-0xaf
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xb0-0xb7
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xb8-0xbf
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xc0-0xc7
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xc8-0xcf
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, // 0xd0-0xd7
