/// Init entry
#[unsafe(no_mangle)]
pub extern "C" fn main() {
    set_current_dir("/").ok();
    info!("[init] current directory set to /");

    let init = ProcessControlBlock::new(DUMMY_ELF);
    *init.name.lock() = "init".to_string();

    setup_rootfs(&init);

    #[cfg(feature = "shell")]
    run_shell(&init);

    #[cfg(feature = "test")]
    run_tests(&init);

    shutdown()
}

fn run_shell(init: &Arc<ProcessControlBlock>) {
    let (pid, _) = spawn_user_process(init, "/musl/busybox", &["sh"]);

    axprocess::wait_pid_spinning(init, pid as isize);
}

#[cfg(feature = "test")]
fn run_tests(init: &Arc<ProcessControlBlock>) {
    musl_basic_tests(init);
    glibc_basic_tests(init);
}

