/// Rootfs setup
fn setup_rootfs(init: &Arc<ProcessControlBlock>) {
    println!("[init] setup rootfs...");

    let _ = create_dir_all("/bin");
    let _ = create_dir_all("/etc");
    let _ = create_dir_all("/root");

    let _ = write("/etc/passwd", b"root:x:0:0:root:/root:/bin/sh\n");
    let _ = write("/etc/group", b"root:x:0:\n");
    let _ = write("/etc/profile", b"export PATH=/bin:/musl:/glibc\n");
    let _ = write("/etc/motd", b"MeteorOS ready\n");

    let (pid, _) =
        spawn_user_process(init, "/musl/busybox", &["sh", "-c", "busybox --install -s /bin"]);

    axprocess::wait_pid_spinning(init, pid as isize);

    println!("[init] rootfs ready");
}

/// Process spawn wrapper
pub fn spawn_user_process(
    parent: &Arc<ProcessControlBlock>,
    app_path: &str,
    args: &[&str],
) -> (usize, Arc<ProcessControlBlock>) {
    let elf_data = match load_elf_from_file(app_path) {
        Ok(data) => data,
        Err(e) => {
            println!("[init] failed to load {}: {}", app_path, e);
            axhal::misc::terminate();
        }
    };

    let child = parent.fork(None);
    let pid = child.getpid();

    *child.name.lock() = app_path.to_string();

    let mut argv = Vec::new();
    argv.push(app_path.to_string());

    for a in args {
        argv.push((*a).to_string());
    }

    let env = vec!["PATH=/bin:/musl:/glibc".to_string(), "HOME=/root".to_string()];
    child.exec(elf_data.as_slice(), argv, env);

    (pid, child)
}

/// shutdown
fn shutdown() -> ! {
    println!("[init] flushing fs...");
    let _ = flush_all();

    println!("[init] poweroff");
    axhal::misc::terminate()
}

