use core::sync::atomic::{AtomicUsize, Ordering};

static INITED_CPUS: AtomicUsize = AtomicUsize::new(0);

fn is_init_ok() -> bool {
    INITED_CPUS.load(Ordering::Acquire) == axconfig::SMP
}

#[cfg(all(feature = "alloc", not(feature = "axmem")))]
fn init_allocator() {
    use axhal::mem::{MemRegionFlags, memory_regions, phys_to_virt};

    let mut max_region_size = 0;
    let mut max_region_start = 0;
    for r in memory_regions() {
        if r.flags.contains(MemRegionFlags::FREE) {
            if r.size > max_region_size {
                max_region_size = r.size;
                max_region_start = r.paddr.as_usize();
            }
        }
    }
    if max_region_size == 0 {
        axlog::error!("No free memory for heap allocator");
    }
    let heap_start = phys_to_virt(max_region_start.into()).as_usize();
    if max_region_size > 4096 {
        max_region_size -= 4096;
    }
    axalloc::global_init(heap_start, max_region_size);
}

/// The main entry point of the ArceOS runtime.
///
/// It is called from the bootstrapping code in [axhal]. `cpu_id` is the ID of
/// the current CPU, and `dtb` is the address of the device tree blob. It
/// finally calls the application's `main` function after all initialization
/// work is done.
///
/// In multi-core environment, this function is called on the primary CPU,
/// and the secondary CPUs call [`rust_main_secondary`].
#[cfg_attr(not(test), unsafe(no_mangle))]
pub extern "C" fn rust_main(_cpu_id: usize, dtb: usize) -> ! {
    ax_println!("{}", LOGO);
    ax_println!(
        "\
        arch = {}\n\
        platform = {}\n\
        target = {}\n\
        smp = {}\n\
        build_mode = {}\n\
        log_level = {}\n\
        ",
        option_env!("AX_ARCH").unwrap_or(""),
        option_env!("AX_PLATFORM").unwrap_or(""),
        option_env!("AX_TARGET").unwrap_or(""),
        option_env!("AX_SMP").unwrap_or(""),
        option_env!("AX_MODE").unwrap_or(""),
        option_env!("AX_LOG").unwrap_or(""),
    );

    match dtb::bootargs(dtb) {
        Some(args) => {
            ax_println!("[axruntime] bootargs: {}", args);
            let port = parse_u16_arg(args, "port", 5555);
            axhal::port::set_port(port);
            let host_port = parse_u16_arg(args, "host_port", 8080);
            axhal::port::set_host_port(host_port);
        }
        None => {
            ax_println!("[axruntime] no bootargs");
        }
    }

    #[cfg(feature = "rtc")]
    ax_println!(
        "Boot at {}\n",
        chrono::DateTime::from_timestamp_nanos(axhal::time::wall_time_nanos() as _),
    );

    axlog::init();
    axlog::set_max_level(option_env!("AX_LOG").unwrap_or("")); // no effect if set `log-level-*` features

    #[cfg(all(feature = "alloc", not(feature = "axmem")))]
    init_allocator();

    #[cfg(feature = "axmem")]
    axmem::init();

    #[cfg(all(feature = "paging", not(feature = "axmem")))]
    // axmm::init_memory_management();
    axhal::platform_init();

    #[cfg(feature = "multitask")]
    axtask::init_scheduler();

    #[cfg(any(feature = "fs", feature = "net", feature = "display"))]
    {
        #[allow(unused_variables)]
        let all_devices = axdriver::init_drivers();

        #[cfg(feature = "fs")]
        axfs::init_filesystems(all_devices.block);

        #[cfg(feature = "net")]
        axnet::init_network(all_devices.net);

        #[cfg(feature = "display")]
        axdisplay::init_display(all_devices.display);
    }

    #[cfg(feature = "smp")]
    self::mp::start_secondary_cpus(cpu_id);

    #[cfg(feature = "irq")]
    {
        init_interrupt();
    }

    #[cfg(all(feature = "tls", not(feature = "multitask")))]
    {
        init_tls();
    }

    INITED_CPUS.fetch_add(1, Ordering::Relaxed);

    while !is_init_ok() {
        core::hint::spin_loop();
    }

    // 使用编译期 AX_TIME 环境变量（来自 Makefile）
    // 通过 Makefile: AX_TIME=$(shell date +%s)
    let epoch_secs = option_env!("AX_TIME").and_then(|s| s.parse::<u64>().ok());

    if let Some(secs) = epoch_secs {
        let now_ns = axhal::time::monotonic_time_nanos();
        let epoch_ns = secs.saturating_mul(1_000_000_000);
        let offset_ns = epoch_ns.saturating_sub(now_ns);
        axhal::time::set_epoch_offset_nanos(offset_ns);
        axlog::info!(
            "[axruntime] wall_time epoch offset set: {} ns (from AX_TIME = {} s)",
            offset_ns,
            secs
        );
    } else {
        axlog::warn!("[axruntime] AX_TIME not set, wall_time falls back to monotonic clock");
    }

    unsafe { main() };

    #[cfg(feature = "multitask")]
    axtask::exit(0);
    #[cfg(not(feature = "multitask"))]
    {
        debug!("main task exited: exit_code={}", 0);
        axhal::misc::terminate();
    }
}

