        {
            axlog::debug!("Page fault at addr={:#x}, flags={:?}", addr.as_usize(), flags);

            #[cfg(feature = "axmem")]
            {
                // 转换 MappingFlags 到 MapPermission
                let mut required = MapPermission::empty();
                if flags.contains(MappingFlags::READ) {
                    required |= MapPermission::R;
                }
                if flags.contains(MappingFlags::WRITE) {
                    required |= MapPermission::W;
                }
                if flags.contains(MappingFlags::EXECUTE) {
                    required |= MapPermission::X;
                }
                if flags.contains(MappingFlags::USER) {
                    required |= MapPermission::U;
                }

                // 尝试通过 sign-extended-32 aliasing 处理页面错误
                #[cfg(feature = "axprocess")]
                if let Some(task) = current_task() {
                    let task_inner = task.inner_exclusive_access();
                    if let Some(process) = task.process.upgrade() {
                        let mut memory_set = process.process_data.memory_set.lock();
                        let handled =
                            memory_set.handle_page_fault((addr.as_usize()).into(), required);
                        if handled {
                            drop(memory_set);
                            axlog::debug!("Page fault handled by process memory set");
                            drop(task_inner);
                            return;
                        }
                        if required.contains(MapPermission::U) {
                            let alias_ok = memory_set
                                .try_alias_sign_extended_32((addr.as_usize()).into(), required);
                            if alias_ok {
                                axlog::debug!("Page fault handled by sign-extended-32 aliasing");
                                drop(memory_set);
                                drop(task_inner);
                                return;
                            }
                        }
                        drop(memory_set);
                    }
                    drop(task_inner);
                }

                // 如果不是用户模式下的页面错误，尝试在内核空间处理
                if !flags.contains(MappingFlags::USER) {
                    axlog::debug!("Trying kernel space for non-user page fault");
                    let mut kernel_space = KERNEL_SPACE.exclusive_access();
                    let handled =
                        kernel_space.handle_page_fault((addr.as_usize()).into(), required);
                    if handled {
                        axlog::debug!("Page fault handled by kernel space");
                        return;
                    } else {
                        axlog::debug!("Kernel space could not handle page fault");
                    }
                }
            }

            axlog::debug!("trap frame: {:#?}", _tf);

            // 如果是用户模式下的页面错误，终止当前进程
            #[cfg(feature = "axprocess")]
