pub unsafe fn sys_writev(fd: c_int, iov: *const iovec, iocnt: c_int) -> isize {
    if iocnt < 0 || iocnt > 1024 {
        return -1;
    }

    // Localize all unsafe pointer/slice operations into a single, minimal unsafe block.
    // Behavior unchanged: iterate the iovec array and write each buffer.
    let mut total = 0isize;
    unsafe {
        let iovs = core::slice::from_raw_parts(iov, iocnt as usize);
        for iov_item in iovs.iter() {
            if iov_item.iov_len == 0 {
                continue;
            }
            let buf = core::slice::from_raw_parts(iov_item.iov_base as *const u8, iov_item.iov_len);
            let ret = sys_write(fd as usize, buf);
            if ret < 0 {
                return ret;
            }
            total += ret;
        }
    }
    total
}

