    filename: *const core::ffi::c_char,
    flags: c_int,
    mode: u32,
) -> c_int {
    // AT_FDCWD = -100 means relative to current working directory
    const AT_FDCWD: isize = -100;
    if filename.is_null() {
        return -1;
    }
    let path = unsafe { CStr::from_ptr(filename) };
    let path_str: String = match path.to_str() {
        Ok(s) => String::from(s),
        Err(_) => {
            let bytes = path.to_bytes();
            let mut s = String::with_capacity(bytes.len());
            for &b in bytes.iter() {
                if b.is_ascii() {
                    s.push(b as char);
                } else {
                    s.push('\u{FFFD}');
                }
            }
            s
        }
    };
    sys::sys_openat(AT_FDCWD as i32, &path_str, flags as usize, mode) as c_int
}

