use bitflags::*;

bitflags! {
    pub struct SignalFlags: u32 {
        const SIGINT    = 1 << 2;
        const SIGILL    = 1 << 4;
        const SIGABRT   = 1 << 6;
        const SIGFPE    = 1 << 8;
        const SIGSEGV   = 1 << 11;
    }
}

impl SignalFlags {
    pub fn check_error(&self) -> Option<(i32, &'static str)> {
        if self.contains(Self::SIGINT) {
            Some((-2, "Killed, SIGINT=2"))
        } else if self.contains(Self::SIGILL) {
            Some((-4, "Illegal Instruction, SIGILL=4"))
        } else if self.contains(Self::SIGABRT) {
            Some((-6, "Aborted, SIGABRT=6"))
        } else if self.contains(Self::SIGFPE) {
            Some((-8, "Erroneous Arithmetic Operation, SIGFPE=8"))
        } else if self.contains(Self::SIGSEGV) {
            Some((-11, "Segmentation Fault, SIGSEGV=11"))
        } else {
            None
        }
    }
}

use super::{ProcessControlBlock, TaskControlBlock, TaskStatus};
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use axsync::Mutex;
use lazy_static::*;

pub struct TaskManager {
    ready_queue: VecDeque<Arc<TaskControlBlock>>,
}

/// A simple FIFO scheduler.
impl TaskManager {
    pub fn new() -> Self {
        Self { ready_queue: VecDeque::new() }
    }
    pub fn add(&mut self, task: Arc<TaskControlBlock>) {
        let pid = task.get_process_id();
        let already_exists = self.ready_queue.iter().any(|t| t.get_process_id() == pid);
        if already_exists {
            return;
        }
        self.ready_queue.push_back(task);
    }
    pub fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        // Try to find a task that's not the Shell process (PID 1)
        // Shell runs in the kernel main thread, not as a scheduled task
        let mut attempts = 0;
        let max_attempts = self.ready_queue.len() + 1;

        while attempts < max_attempts {
            let task = self.ready_queue.pop_front();
            if let Some(ref t) = task {
                let pid = t.get_process_id();
                if pid == 1 {
                    // This is the Shell task, put it back at the end and try next
                    self.ready_queue.push_back(Arc::clone(t));
                    attempts += 1;
                    continue;
                }
                return task;
            } else {
                return None;
            }
        }

        None
    }
}

lazy_static! {
    pub static ref TASK_MANAGER: Mutex<TaskManager> = Mutex::new(TaskManager::new());
    pub static ref PID2PCB: Mutex<BTreeMap<usize, Arc<ProcessControlBlock>>> =
        Mutex::new(BTreeMap::new());
}

pub fn add_task(task: Arc<TaskControlBlock>) {
    (&*TASK_MANAGER).lock().add(task);
}

pub fn wakeup_task(task: Arc<TaskControlBlock>) {
    let _pid = task.get_process_id();
    task.ax_task.set_state(axtask::TaskState::Ready);
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    add_task(task);
}

pub fn block_current_on_wait_queue() {
    unreachable!("block_current_on_wait_queue should not be called directly; use block_current_and_run_next instead")
}

// 移除任何进程ID等于 pid 的排队任务。
pub fn remove_task_by_pid(pid: usize) {
    let mut mgr = (&*TASK_MANAGER).lock();
    let before = mgr.ready_queue.len();
    mgr.ready_queue.retain(|t| t.get_process_id() != pid);
    let after = mgr.ready_queue.len();
    axlog::warn!(
        "[TaskManager] remove_task_by_pid {}: removed {} entries, new size {}",
        pid,
        before - after,
        after
    );
}

pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    (&*TASK_MANAGER).lock().fetch()
}

pub fn pid2process(pid: usize) -> Option<Arc<ProcessControlBlock>> {
    let map = (&*PID2PCB).lock();
    map.get(&pid).map(Arc::clone)
}

/// 列出所有进程的 (pid, ppid) 对
pub fn list_pids() -> Vec<(usize, usize)> {
    let map = (&*PID2PCB).lock();
    let mut v: Vec<(usize, usize)> = Vec::new();
    for (pid, pcb) in map.iter() {
        let parent_lock = pcb.parent.lock();
        let ppid = if let Some(w) = parent_lock.as_ref() {
            if let Some(parent) = w.upgrade() { parent.getpid() } else { 0usize }
        } else {
            0usize
        };
        v.push((*pid, ppid));
    }
    v
}

pub fn insert_into_pid2process(pid: usize, process: Arc<ProcessControlBlock>) {
    (&*PID2PCB).lock().insert(pid, process);
}

pub fn remove_from_pid2process(pid: usize) {
    let mut map = (&*PID2PCB).lock();
    if map.remove(&pid).is_none() {
        panic!("cannot find pid {} in pid2task!", pid);
    }
}

