// 可回收ID分配器
pub struct RecycleAllocator {
    current: usize,
    recycled: Vec<usize>,
}

impl RecycleAllocator {
    pub fn new() -> Self {
        RecycleAllocator {
            current: 1, // 从 1 开始，因为 PID 0 保留给 Idle 进程
            recycled: Vec::new(),
        }
    }
    pub fn alloc(&mut self) -> usize {
        if let Some(id) = self.recycled.pop() {
            id
        } else {
            self.current += 1;
            self.current - 1
        }
    }
    pub fn dealloc(&mut self, id: usize) {
        assert!(id < self.current);
        assert!(id != 0, "Cannot deallocate PID 0 (reserved for Idle process)");
        assert!(!self.recycled.iter().any(|i| *i == id), "id {} has been deallocated!", id);
        self.recycled.push(id);
    }
}

pub struct PidAllocator {
    current: usize,
    recycled: Vec<usize>,
    limit: usize,
}

impl PidAllocator {
    pub fn new() -> Self {
        PidAllocator { current: 1, recycled: Vec::new(), limit: 32768 }
    }
    pub fn alloc(&mut self) -> usize {
        if self.current < self.limit {
            let id = self.current;
            self.current += 1;
            id
        } else {
            if let Some(id) = self.recycled.pop() {
                id
            } else {
                let id = self.current;
                self.current += 1;
                id
            }
        }
    }
    pub fn dealloc(&mut self, id: usize) {
        assert!(id < self.current);
        assert!(id != 0, "Cannot deallocate PID 0");
        assert!(!self.recycled.iter().any(|i| *i == id), "id {} has been deallocated!", id);
        self.recycled.push(id);
    }
}

