// 计算内核栈在虚拟地址空间中的位置
pub fn kernel_stack_position(kstack_id: usize) -> (usize, usize) {
    // 内核栈从 TRAP_CONTEXT_BASE 向下分配，每个内核栈占用 KERNEL_STACK_SIZE + PAGE_SIZE（保护页）
    let top = TRAP_CONTEXT_BASE - PAGE_SIZE - kstack_id * (KERNEL_STACK_SIZE + PAGE_SIZE);
    let bottom = top - KERNEL_STACK_SIZE;
    axlog::debug!(
        "kernel_stack_position: kstack_id={}, bottom={:#x}, top={:#x}",
        kstack_id,
        bottom,
        top
    );
    (bottom, top)
}

/// 获取指定内核栈ID对应的物理页帧列表
pub fn get_kstack_frames(kstack_id: usize) -> Vec<PhysPageNum> {
    let frames_lock = KSTACK_FRAMES.exclusive_access();
    let frames = frames_lock.get(&kstack_id).expect("Kernel stack frames not found");

    frames.iter().map(|f| f.ppn).collect()
}

pub struct KernelStack(pub usize);

pub fn kstack_alloc() -> KernelStack {
    let kstack_id = KSTACK_ALLOCATOR.exclusive_access().alloc();
    axlog::debug!("kstack_alloc: allocated kstack_id={}", kstack_id);
    let (kstack_bottom, kstack_top) = kernel_stack_position(kstack_id);

    // 计算需要的页数
    let kstack_size_bytes = kstack_top - kstack_bottom;
    let num_pages = (kstack_size_bytes + axconfig::PAGE_SIZE - 1) / axconfig::PAGE_SIZE;

    axlog::debug!(
        "kstack_alloc: kstack_id={}, range=[{:#x}, {:#x}), {} pages",
        kstack_id,
        kstack_bottom,
        kstack_top,
        num_pages
    );

    use axmem::{VirtAddr, frame_alloc};
    let mut frames = alloc::vec::Vec::new();
    for _ in 0..num_pages {
        if let Some(frame) = frame_alloc() {
            if frame.ppn.0 == 0 {
                panic!("kstack_alloc: Allocated frame with PPN 0!");
            }
            frames.push(frame);
        } else {
            panic!("Failed to allocate physical frame for kernel stack");
        }
    }
    // 映射到 KERNEL_SPACE
    {
        let mut kernel_space = KERNEL_SPACE.exclusive_access();
        for (i, frame) in frames.iter().enumerate() {
            let va = VirtAddr::from(kstack_bottom + i * axconfig::PAGE_SIZE);
            let ppn = frame.ppn;
            let flags = MapPermission::R | MapPermission::W;
            kernel_space.map_existing_page(va, ppn, flags);
            axlog::debug!(
                "kstack_alloc: Mapped VA {:#x} -> PPN {:#x} in KERNEL_SPACE",
                va.0,
                ppn.0
            );
        }
    }

    // 保存物理页帧列表，以便后续释放
    KSTACK_FRAMES.exclusive_access().insert(kstack_id, frames);

    axlog::debug!("kstack_alloc: kstack_id={} physical frames allocated", kstack_id);

    KernelStack(kstack_id)
}

impl Drop for KernelStack {
    fn drop(&mut self) {
        {
            use axmem::{KERNEL_SPACE, VirtAddr};
            let (bottom, top) = self.get_range();
            let mut kernel_space = KERNEL_SPACE.exclusive_access();
            let mut va = bottom;
            while va < top {
                kernel_space.unmap_one_page(VirtAddr::from(va));
                va += axconfig::PAGE_SIZE;
            }
        }
        KSTACK_FRAMES.exclusive_access().remove(&self.0);
        // 释放内核栈ID
        KSTACK_ALLOCATOR.exclusive_access().dealloc(self.0);
    }
}

impl KernelStack {
    #[allow(unused)]
    pub fn push_on_top<T>(&self, value: T) -> *mut T
    where
        T: Sized,
    {
        let kernel_stack_top = self.get_top();
        let ptr_mut = (kernel_stack_top - core::mem::size_of::<T>()) as *mut T;
        unsafe {
            *ptr_mut = value;
        }
        ptr_mut
    }

    pub fn get_id(&self) -> usize {
        self.0
    }

    /// 获取内核栈的范围（底部，顶部）
    pub fn get_range(&self) -> (usize, usize) {
        kernel_stack_position(self.0)
    }

    pub fn get_top(&self) -> usize {
        let (_, kernel_stack_top) = kernel_stack_position(self.0);
        kernel_stack_top
    }

    /// 获取内核栈顶部的陷阱帧指针
    pub fn get_first_trap_frame(&self) -> *mut axhal::arch::TrapFrame {
        let kstack_top = self.get_top();
        (kstack_top - core::mem::size_of::<axhal::arch::TrapFrame>()) as *mut axhal::arch::TrapFrame
    }
}

